// Shared UI Components
const Badge: React.FC<{ label: string; tone?: 'pink' | 'blue' | 'amber' }> = ({ label, tone = 'blue' }) => {
  const toneMap: Record<string, string> = {
    pink: 'bg-pink-100 text-pink-700',
    blue: 'bg-blue-100 text-blue-700',
    amber: 'bg-amber-100 text-amber-700',
  };
  return (
    <span className={`text-xs font-medium px-2 py-0.5 rounded-full ${toneMap[tone]} shadow-sm`}>{label}</span>
  );
};

const RatingStars: React.FC<{ rating: number }> = ({ rating }) => {
  const stars = Array.from({ length: 5 }).map((_, i) => i < Math.round(rating));
  return (
    <div className="flex items-center gap-0.5">
      {stars.map((on, i) => (
        <svg key={i} className={`w-4 h-4 ${on ? 'text-yellow-400' : 'text-gray-300'}`} fill="currentColor" viewBox="0 0 20 20">
          <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.802 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118L10 13.347l-2.935 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L3.43 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
        </svg>
      ))}
    </div>
  );
};

const ColorDots: React.FC<{ colors: string[]; selected?: string; onSelect?: (c: string) => void }> = ({ colors, selected, onSelect }) => {
