    let list = PRODUCTS.filter((p) =>
      (selectedCategory === 'All' || p.category === selectedCategory) &&
      (search.trim() === '' || p.name.toLowerCase().includes(search.toLowerCase()))
    );
    if (sort === 'price-asc') list = [...list].sort((a, b) => a.price - b.price);
    if (sort === 'price-desc') list = [...list].sort((a, b) => b.price - a.price);
    return list;
  }, [selectedCategory, sort, search]);

  return (
    <div className="max-w-6xl mx-auto px-4">
      <div className="mt-8 flex flex-col gap-4">
        <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-3">
          <h1 className="text-2xl font-extrabold text-gray-900">Shop</h1>
          <div className="flex items-center gap-2">
            <input value={search} onChange={(e) => setSearch(e.target.value)} placeholder="Search products..." className="px-3 py-2 rounded-lg border border-gray-200 focus:outline-none w-60" />
            <select value={sort} onChange={(e) => setSort(e.target.value as any)} className="px-3 py-2 rounded-lg border border-gray-200 bg-white">
              <option value="featured">Featured</option>
              <option value="price-asc">Price: Low to High</option>
              <option value="price-desc">Price: High to Low</option>
            </select>
          </div>
        </div>
        <div className="flex flex-wrap gap-2">
          {['All', ...categories].map((c) => (
            <button
              key={c}
              onClick={() => { setSelectedCategory(c); navigate(c === 'All' ? '/shop' : `/shop?category=${encodeURIComponent(c)}`); }}
              className={`px-4 py-2 rounded-lg transition ${selectedCategory === c ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
            >
              {c}
            </button>
          ))}
        </div>
        <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {filtered.map((p) => (
            <ProductCard
              key={p.id}
              product={p}
              onAddToCart={(prod) => onAddToCart(prod)}
              onView={(prod) => navigate(`/product/${prod.id}`)}
            />
          ))}
          {filtered.length === 0 && (
            <div className="col-span-full text-center py-16 bg-white rounded-xl shadow-md">
              <p className="text-gray-700 font-semibold">No products found</p>
              <p className="text-gray-500 text-sm">Try adjusting your filters</p>
              <div className="mt-4">
                <button onClick={() => { setSelectedCategory('All'); setSearch(''); setSort('featured'); navigate('/shop'); }} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Reset filters</button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

