// App Routes with shared cart state
const AppRoutes: React.FC = () => {
  const [cart, setCart] = useState<CartItem[]>(() => {
    try {
      const raw = localStorage.getItem('chromawear_cart');
      return raw ? JSON.parse(raw) as CartItem[] : [];
    } catch {
      return [];
    }
  });
  const [toast, setToast] = useState<string>('');

  useEffect(() => {
    localStorage.setItem('chromawear_cart', JSON.stringify(cart));
  }, [cart]);

  const addToCart = (product: Product, qty = 1, color?: string) => {
    setCart((prev) => {
      const idx = prev.findIndex((i) => i.product.id === product.id && i.color === color);
      if (idx >= 0) {
        const copy = [...prev];
        copy[idx] = { ...copy[idx], qty: copy[idx].qty + qty };
        return copy;
      }
      return [...prev, { product, qty, color }];
    });
    setToast(`${product.name} added to cart`);
  };

  const updateQty = (id: string, newQty: number, color?: string) => {
    setCart((prev) => prev.map((i) => (i.product.id === id && i.color === color) ? { ...i, qty: newQty } : i));
  };

  const removeItem = (id: string, color?: string) => {
    setCart((prev) => prev.filter((i) => !(i.product.id === id && i.color === color)));
  };

  const clearCart = () => setCart([]);

  useEffect(() => {
    if (!toast) return;
    const t = setTimeout(() => setToast(''), 1800);
    return () => clearTimeout(t);
  }, [toast]);

  const cartCount = cart.reduce((sum, i) => sum + i.qty, 0);

  return (
    <div className="min-h-screen bg-gradient-to-b from-white to-blue-50/30">
      <Navbar cartCount={cartCount} />
      <main className="pb-10">
        <Routes>
          <Route path="/" element={<HomePage onAddToCart={(p) => addToCart(p, 1)} />} />
          <Route path="/shop" element={<ShopPage onAddToCart={(p) => addToCart(p, 1)} />} />
          <Route path="/product/:id" element={<ProductPage onAddCustom={(p, q, c) => addToCart(p, q, c)} />} />
          <Route path="/about" element={<AboutPage />} />
          <Route path="/cart" element={<CartPage items={cart} onUpdateQty={(id, qty, color) => updateQty(id, qty, color)} onRemove={(id, color) => removeItem(id, color)} onClear={() => clearCart()} />} />
          <Route path="*" element={
            <div className="max-w-6xl mx-auto px-4 py-16">
              <div className="bg-white rounded-xl shadow-md p-8 text-center">
                <p className="text-gray-700 font-semibold">Page not found</p>
                <Link to="/" className="mt-4 inline-block px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Go home</Link>
              </div>
            </div>
          } />
        </Routes>
      </main>
      <Footer />

      {/* Toast */}
      {toast && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-gray-900 text-white px-4 py-2 rounded-lg shadow-lg">{toast}</div>
      )}

      {/* Floating Cart CTA */}
      <Link to="/cart" className="fixed bottom-6 right-6 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition shadow-lg flex items-center gap-2">
        <svg className="w-5 h-5" fill="none" stroke="currentColor" strokeWidth="1.5" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 3h1.386a1.125 1.125 0 011.07.78l.383 1.148M7.5 14.25h9.563a1.125 1.125 0 001.071-.78l2.121-6.363A1.125 1.125 0 0019.25 6H5.089m2.411 8.25L5.1 4.928M7.5 14.25L5.1 4.928M7.5 14.25a1.5 1.5 0 11-3 0m12.75 0a1.5 1.5 0 11-3 0" />
        </svg>
        <span>Cart ({cartCount})</span>
      </Link>
    </div>
  );
};

